import * as React from 'react';
import _keys from 'lodash/keys';
import { TrayWidget } from './TrayWidget';
import { Application } from '../Application';
import { TrayItemWidget } from './TrayItemWidget';
import { DefaultNodeModel } from '@projectstorm/react-diagrams';
import { CanvasWidget } from '@projectstorm/react-canvas-core';
import { DemoCanvasWidget } from './DemoCanvasWidget';
import styled from '@emotion/styled';

export interface BodyWidgetProps {
	app: Application;
}

namespace S {
	export const Body = styled.div`
		flex-grow: 1;
		display: flex;
		flex-direction: column;
		min-height: 100%;
	`;

	export const Header = styled.div`
		display: flex;
		background: rgb(30, 30, 30);
		flex-grow: 0;
		flex-shrink: 0;
		color: white;
		font-family: Helvetica, Arial, sans-serif;
		padding: 10px;
		align-items: center;
	`;

	export const Content = styled.div`
		display: flex;
		flex-grow: 1;
	`;

	export const Layer = styled.div`
		position: relative;
		flex-grow: 1;
	`;
}

export class BodyWidget extends React.Component<BodyWidgetProps> {
  state = {
    userInput: '', // 用于存储输入框的内容
    response: null, // 用于存储后端返回的响应
  };

  handleInputChange = (event: React.ChangeEvent<HTMLInputElement>) => {
  this.setState({ userInput: event.target.value });
  };

  handleButtonClick = async () => {
    const input = this.state.userInput;
    try {
      // 使用fetch发送请求到后端
      const response = await fetch('你的Flask后端URL', {
        method: 'POST', // 或者'GET'，根据你的后端API设计
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ input: input }), // 发送输入框的内容
      });
      const data = await response.json(); // 解析JSON响应
      this.setState({ response: data }); // 更新状态以存储响应
    } catch (error) {
      console.error('请求失败:', error);
    }
  };


	render() {
		return (
			<S.Body>
				<S.Header>
					<div className="title">MICA - Moudle Instantiate & Connect Auto</div>
				</S.Header>
				<S.Content>
          <input
            type="text"
            value={this.state.userInput}
            onChange={this.handleInputChange}
            style={{ width: '100%', height: '20px', boxSizing: 'border-box' }} // 调整宽度和高度
          />
          <button onClick={this.handleButtonClick} style={{ height: '20px', margin: '0' }}>发送</button>
          {/* 根据需要显示后端响应 */}
          {this.state.response && <div>后端响应: {JSON.stringify(this.state.response)}</div>}
        </S.Content>
				<S.Content>
					<TrayWidget>
						<TrayItemWidget model={{ type: 'in' }} name="In Node" color="rgb(192,255,0)" />
						<TrayItemWidget model={{ type: 'out' }} name="Out Node" color="rgb(0,192,255)" />
					</TrayWidget>
					<S.Layer
						onDrop={(event) => {
							var data = JSON.parse(event.dataTransfer.getData('storm-diagram-node'));
							var nodesCount = _keys(this.props.app.getDiagramEngine().getModel().getNodes()).length;

							var node: DefaultNodeModel | null = null;
							if (data.type === 'in') {
								node = new DefaultNodeModel('Node ' + (nodesCount + 1), 'rgb(192,255,0)');
								node.addInPort('In');
							} else {
								node = new DefaultNodeModel('Node ' + (nodesCount + 1), 'rgb(0,192,255)');
								node.addOutPort('Out');
							}
							var point = this.props.app.getDiagramEngine().getRelativeMousePoint(event);
							node.setPosition(point);
							this.props.app.getDiagramEngine().getModel().addNode(node);
							this.forceUpdate();
						}}
						onDragOver={(event) => {
							event.preventDefault();
						}}
					>
						<DemoCanvasWidget>
							<CanvasWidget engine={this.props.app.getDiagramEngine()} />
						</DemoCanvasWidget>
					</S.Layer>
				</S.Content>
			</S.Body>
		);
	}
}
